import{_ as a,o as t,c as r,a2 as i}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"倒排索引、Analyzer、Tokenizer 与 Mapping","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"search-index-analysis-mapping"},"headers":[],"relativePath":"05-backend-data/notes/07-cache-messaging-storage/12-search-index-analyzer-mapping.md","filePath":"05-backend-data/notes/07-cache-messaging-storage/12-search-index-analyzer-mapping.md","lastUpdated":null}'),n={name:"05-backend-data/notes/07-cache-messaging-storage/12-search-index-analyzer-mapping.md"};function l(o,e,d,p,s,h){return t(),r("div",null,[...e[0]||(e[0]=[i(`<h1 id="倒排索引、analyzer、tokenizer-与-mapping" tabindex="-1">倒排索引、Analyzer、Tokenizer 与 Mapping <a class="header-anchor" href="#倒排索引、analyzer、tokenizer-与-mapping" aria-label="Permalink to &quot;倒排索引、Analyzer、Tokenizer 与 Mapping&quot;">​</a></h1><p>全文搜索把文本转换为可检索 term，并用倒排表从 term 定位文档。Mapping 决定字段类型、索引方式和可查询能力；字段一旦以错误类型建立，通常需要新索引重建，而不是原地修正历史 posting。</p><h2 id="_1-能力边界与机制图" tabindex="-1">1. 能力边界与机制图 <a class="header-anchor" href="#_1-能力边界与机制图" aria-label="Permalink to &quot;1. 能力边界与机制图&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;事实输入&quot;] --&gt; B[&quot;索引/处理机制&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;查询或派生输出&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;验证与观测&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;失败恢复/重建&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这条链路的关键不变量是“索引时与查询时使用兼容的分析规则”。排查时保存原文、Analyzer 名称与版本、Analyze API token 序列、mapping 版本和目标索引别名，才能判断问题发生在切词、字段类型还是发布切换。</p><h2 id="_2-倒排索引" tabindex="-1">2. 倒排索引 <a class="header-anchor" href="#_2-倒排索引" aria-label="Permalink to &quot;2. 倒排索引&quot;">​</a></h2><p>机制：term dictionary 保存词项，posting list 保存包含该词项的文档及可选词频、位置和 offset。</p><p>实际使用：适合从词找文档、布尔组合和相关性评分。</p><p>主要失败：把它当主键数据库会失去事务、约束和权威写入。</p><p>验证方法：用 _termvectors、profile、段统计观察 term 与 posting。</p><p>取舍：写入需要分析、段合并和额外存储，换取读检索。</p><p>生产实现 倒排索引 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_3-segment" tabindex="-1">3. Segment <a class="header-anchor" href="#_3-segment" aria-label="Permalink to &quot;3. Segment&quot;">​</a></h2><p>机制：Lucene 将写入形成不可变 segment，refresh 后可搜索，后台 merge 合并小段。</p><p>实际使用：理解 near-real-time、删除标记和合并 I/O。</p><p>主要失败：把 refresh 等同持久提交或立即 merge。</p><p>验证方法：观察 refresh time、segment count、merge throttle 与磁盘。</p><p>取舍：过短 refresh 提升可见性但增加小段和资源。</p><p>生产实现 Segment 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_4-character-filter" tabindex="-1">4. Character filter <a class="header-anchor" href="#_4-character-filter" aria-label="Permalink to &quot;4. Character filter&quot;">​</a></h2><p>机制：在 tokenizer 前转换字符并维护 offset 映射。</p><p>实际使用：清理 HTML、统一特定字符或映射规则。</p><p>主要失败：无边界删除字符会让高亮 offset 与原文错位。</p><p>验证方法：用 Analyze API 查看每阶段 token 与 offset。</p><p>取舍：预处理越强，原文语义损失越大。</p><p>生产实现 Character filter 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_5-tokenizer" tabindex="-1">5. Tokenizer <a class="header-anchor" href="#_5-tokenizer" aria-label="Permalink to &quot;5. Tokenizer&quot;">​</a></h2><p>机制：把字符流切为 token，并产生 position 与 offsets。</p><p>实际使用：standard、keyword、whitespace 等按语言和字段选择。</p><p>主要失败：中文直接 whitespace 会把无空格句子当整体。</p><p>验证方法：对真实多语言语料运行 Analyze API。</p><p>取舍：更细粒度召回高但索引和噪声增加。</p><p>生产实现 Tokenizer 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_6-token-filter" tabindex="-1">6. Token filter <a class="header-anchor" href="#_6-token-filter" aria-label="Permalink to &quot;6. Token filter&quot;">​</a></h2><p>机制：对 token 小写化、停用、同义、词干或 n-gram。</p><p>实际使用：统一大小写、形态或业务同义词。</p><p>主要失败：索引时同义扩展会放大索引且更新需重建。</p><p>验证方法：比较索引 analyzer 与 search analyzer 的 token graph。</p><p>取舍：召回提升常伴随精度下降与运维成本。</p><p>生产实现 Token filter 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_7-analyzer" tabindex="-1">7. Analyzer <a class="header-anchor" href="#_7-analyzer" aria-label="Permalink to &quot;7. Analyzer&quot;">​</a></h2><p>机制：由 char filter、tokenizer、token filters 构成，应用于 text 索引与查询。</p><p>实际使用：为标题、正文、代码、中文分别定义。</p><p>主要失败：索引与查询 analyzer 不兼容会导致查不到。</p><p>验证方法：保存 golden corpus 的输入、tokens 与预期命中。</p><p>取舍：一个万能 analyzer 无法同时优化全部字段。</p><p>生产实现 Analyzer 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_8-text-与-keyword" tabindex="-1">8. text 与 keyword <a class="header-anchor" href="#_8-text-与-keyword" aria-label="Permalink to &quot;8. text 与 keyword&quot;">​</a></h2><p>机制：text 经分析用于全文；keyword 保留整体用于精确过滤、排序与聚合。</p><p>实际使用：用 multi-fields 同时提供全文和精确能力。</p><p>主要失败：在 text 上做聚合或把长正文设 keyword。</p><p>验证方法：检查 mapping 与 field capabilities。</p><p>取舍：多字段增加索引和 doc values 空间。</p><p>生产实现 text 与 keyword 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_9-mapping" tabindex="-1">9. Mapping <a class="header-anchor" href="#_9-mapping" aria-label="Permalink to &quot;9. Mapping&quot;">​</a></h2><p>机制：定义字段类型、analyzer、doc_values、index、dynamic 等。</p><p>实际使用：固定公开索引契约并控制动态字段。</p><p>主要失败：无限 dynamic keys 造成 mapping explosion。</p><p>验证方法：设置 mapping limit、检查 rejected 与 field count。</p><p>取舍：严格 mapping 增加发布协调但保护集群。</p><p>生产实现 Mapping 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_10-doc-values" tabindex="-1">10. Doc values <a class="header-anchor" href="#_10-doc-values" aria-label="Permalink to &quot;10. Doc values&quot;">​</a></h2><p>机制：面向列式访问的磁盘结构，用于排序、聚合和脚本。</p><p>实际使用：keyword、numeric、date 的聚合排序。</p><p>主要失败：把大型不需要聚合字段全部保留 doc_values。</p><p>验证方法：用 field usage/profile 与磁盘评估。</p><p>取舍：关闭节省空间但失去高效聚合排序。</p><p>生产实现 Doc values 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_11-nested-与-object" tabindex="-1">11. Nested 与 object <a class="header-anchor" href="#_11-nested-与-object" aria-label="Permalink to &quot;11. Nested 与 object&quot;">​</a></h2><p>机制：object 数组会扁平化字段关系，nested 将每项作为隐藏文档保持配对。</p><p>实际使用：订单 items 需保持 sku 与 quantity 同项关系时用 nested。</p><p>主要失败：用普通 object 查询导致跨数组元素错误匹配。</p><p>验证方法：构造交叉数组反例验证 nested query。</p><p>取舍：nested 写入、查询和文档数成本更高。</p><p>生产实现 Nested 与 object 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_12-方案比较" tabindex="-1">12. 方案比较 <a class="header-anchor" href="#_12-方案比较" aria-label="Permalink to &quot;12. 方案比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>主要收益</th><th>关键边界</th></tr></thead><tbody><tr><td>text</td><td>全文相关性</td><td>不能直接精确聚合</td></tr><tr><td>keyword</td><td>精确过滤排序</td><td>不分词</td></tr><tr><td>object</td><td>简单对象</td><td>数组字段关系会扁平</td></tr><tr><td>nested</td><td>保持数组项关系</td><td>隐藏文档与查询成本</td></tr><tr><td>flattened</td><td>动态键集合</td><td>类型/查询能力受限</td></tr></tbody></table><h2 id="_13-完整案例-多语言商品搜索" tabindex="-1">13. 完整案例：多语言商品搜索 <a class="header-anchor" href="#_13-完整案例-多语言商品搜索" aria-label="Permalink to &quot;13. 完整案例：多语言商品搜索&quot;">​</a></h2><h3 id="输入与约束" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>中文、英文商品标题与品牌；必须支持品牌精确过滤和标题召回；原始数据库仍是事实源。</p><h3 id="处理步骤" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>为 title 定义中文/英文策略并以语言字段路由，不假定同一 tokenizer 适合所有语言。</li><li>title 使用 text，增加 title.keyword；brand 使用 keyword 并配置规范化。</li><li>用 500 条真实查询建立 golden corpus，记录 tokens、期望结果和不应命中。</li><li>创建版本化索引 products-v3，批量回填后别名切换。</li><li>观测零结果率、nDCG/人工判定、segment 与 merge。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>标题按语言检索，品牌精确过滤，mapping 可版本化回滚。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>Analyze API token 与预期一致；同义词更新不破坏旧查询；别名切换前后文档版本对账。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>将中文标题用 whitespace 后大量零结果；修正 tokenizer 并新建索引重建，不能只改 mapping 期待旧 posting 改变。</p><h3 id="完成判断" tabindex="-1">完成判断 <a class="header-anchor" href="#完成判断" aria-label="Permalink to &quot;完成判断&quot;">​</a></h3><p>多语言商品索引完成的证据包括：中英混合 golden query 的 token 与命中集稳定、<code>brand.keyword</code> 聚合不受文本切词影响、旧索引到新索引的源文档版本无缺口，并且别名回退能够恢复旧查询行为。</p><h2 id="_14-完整案例-订单-items-查询" tabindex="-1">14. 完整案例：订单 items 查询 <a class="header-anchor" href="#_14-完整案例-订单-items-查询" aria-label="Permalink to &quot;14. 完整案例：订单 items 查询&quot;">​</a></h2><h3 id="输入与约束-1" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束-1" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>一个订单含 [{sku:A,qty:1},{sku:B,qty:10}]，查询 sku=A 且 qty&gt;=10 不应命中。</p><h3 id="处理步骤-1" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤-1" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>先用 object mapping 建反例，确认数组字段扁平后会交叉匹配。</li><li>新索引将 items 映射 nested。</li><li>nested query 在同一 nested path 组合 sku 与 quantity。</li><li>数据库主键/version 作为外部版本重建。</li><li>比较 nested 文档数量与查询延迟。</li></ol><h3 id="输出-1" tabindex="-1">输出 <a class="header-anchor" href="#输出-1" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>只有同一 item 同时满足条件才命中。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>反例订单不命中；正确 A:10 订单命中；profile 显示可接受成本。</p><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>只在应用结果后过滤会让分页总数和聚合错误；必须在正确 nested 模型中查询。</p><h3 id="完成判断-1" tabindex="-1">完成判断 <a class="header-anchor" href="#完成判断-1" aria-label="Permalink to &quot;完成判断&quot;">​</a></h3><p>订单 items 案例只有在 object 反例确实误命中、nested 版本消除交叉匹配、正确的 <code>A:10</code> 样例仍命中，并完成 nested 文档膨胀与查询 profile 基线后才验收。</p><h2 id="_15-失败注入矩阵" tabindex="-1">15. 失败注入矩阵 <a class="header-anchor" href="#_15-失败注入矩阵" aria-label="Permalink to &quot;15. 失败注入矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>注入点</th><th>应观察的系统行为</th><th>不允许的结果</th></tr></thead><tbody><tr><td>输入中加入未知字段/极端长度</td><td>indexing_rate 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>暂停一个处理节点</td><td>refresh_time 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>让下游返回429或503</td><td>segment_count 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>制造重复与乱序版本</td><td>merge_time 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>使磁盘达到高水位</td><td>mapping_field_count 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>让请求在提交后断线</td><td>rejected_writes 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>撤销一个租户权限</td><td>disk_watermark 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>使后台任务积压超过SLO</td><td>analyze_golden_failures 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr></tbody></table><h2 id="_16-调试路径与观测信号" tabindex="-1">16. 调试路径与观测信号 <a class="header-anchor" href="#_16-调试路径与观测信号" aria-label="Permalink to &quot;16. 调试路径与观测信号&quot;">​</a></h2><ol><li><code>indexing_rate</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>refresh_time</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>segment_count</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>merge_time</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>mapping_field_count</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>rejected_writes</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>disk_watermark</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>analyze_golden_failures</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>zero_result_rate</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>reindex_lag</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li></ol><p>零结果或召回突变时，先对同一原文运行 Analyze API，比对 character filter、tokenizer、token filter 的逐阶段输出；再核对字段实际 mapping、目标 alias 和 segment 中的文档版本。只有 token 一致后才进入评分与查询排障，避免用 BM25 参数掩盖切词错误。</p><h2 id="_17-性能、安全与运维边界" tabindex="-1">17. 性能、安全与运维边界 <a class="header-anchor" href="#_17-性能、安全与运维边界" aria-label="Permalink to &quot;17. 性能、安全与运维边界&quot;">​</a></h2><ol><li>所有用户输入有长度、结构、复杂度和超时上限；对 倒排索引、Analyzer、Tokenizer 与 Mapping 的实现要给出责任人和可执行验证。</li><li>租户与权限条件来自认证主体，不信任请求正文；对 倒排索引、Analyzer、Tokenizer 与 Mapping 的实现要给出责任人和可执行验证。</li><li>重试有总预算、退避、抖动和幂等保护；对 倒排索引、Analyzer、Tokenizer 与 Mapping 的实现要给出责任人和可执行验证。</li><li>派生数据能从事实源按明确水位重建；对 倒排索引、Analyzer、Tokenizer 与 Mapping 的实现要给出责任人和可执行验证。</li><li>敏感正文不进入普通日志、指标标签或公开快照；对 倒排索引、Analyzer、Tokenizer 与 Mapping 的实现要给出责任人和可执行验证。</li><li>容量按峰值写入、查询、恢复和副本同时估算；对 倒排索引、Analyzer、Tokenizer 与 Mapping 的实现要给出责任人和可执行验证。</li><li>发布采用版本化结构、canary、对账和回退窗口；对 倒排索引、Analyzer、Tokenizer 与 Mapping 的实现要给出责任人和可执行验证。</li><li>删除覆盖索引、缓存、快照与下游派生系统；对 倒排索引、Analyzer、Tokenizer 与 Mapping 的实现要给出责任人和可执行验证。</li><li>依赖不可用时核心正确性不由降级路径破坏；对 倒排索引、Analyzer、Tokenizer 与 Mapping 的实现要给出责任人和可执行验证。</li><li>运行手册包含暂停、恢复、验证和人工升级条件；对 倒排索引、Analyzer、Tokenizer 与 Mapping 的实现要给出责任人和可执行验证。</li></ol><h2 id="_18-综合练习与验收" tabindex="-1">18. 综合练习与验收 <a class="header-anchor" href="#_18-综合练习与验收" aria-label="Permalink to &quot;18. 综合练习与验收&quot;">​</a></h2><p>为“多语言商品搜索”实现最小生产链路，并把“订单 items 查询”作为不同约束下的对照。提交配置、请求/响应、数据样例、故障脚本和观测面板。</p><ul><li>[ ] 验收 1：倒排索引 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 2：Segment 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 3：Character filter 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 4：Tokenizer 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 5：Token filter 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 6：Analyzer 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 7：text 与 keyword 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 8：Mapping 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] Analyzer golden set 覆盖中文、英文、标点、大小写、同义词和空 token，并保存预期 token 序列。</li><li>[ ] Mapping 变更通过新索引重建、源版本对账、alias canary 和可执行回退完成发布。</li><li>[ ] Nested 方案记录内部文档放大倍数、磁盘水位与 p95 profile，避免只验证查询正确性。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://docs.opensearch.org/latest/mappings/" target="_blank" rel="noreferrer">OpenSearch 3.7 Mapping</a>（访问日期：2026-07-17）</li><li><a href="https://docs.opensearch.org/latest/api-reference/analyze-apis/" target="_blank" rel="noreferrer">OpenSearch Analyze API</a>（访问日期：2026-07-17）</li><li><a href="https://www.elastic.co/docs/manage-data/data-store/mapping" target="_blank" rel="noreferrer">Elasticsearch Mapping</a>（访问日期：2026-07-17）</li><li><a href="https://lucene.apache.org/core/" target="_blank" rel="noreferrer">Apache Lucene Index File Formats</a>（访问日期：2026-07-17）</li><li><a href="https://docs.opensearch.org/latest/version-history/" target="_blank" rel="noreferrer">OpenSearch 3.7 version history</a>（访问日期：2026-07-17）</li></ul>`,115)])])}const k=a(n,[["render",l]]);export{u as __pageData,k as default};
